class MyStack {
    private java.util.Queue<Integer> q1;
    private java.util.Queue<Integer> q2;

    public MyStack() {
        q1 = new java.util.LinkedList<>();
        q2 = new java.util.LinkedList<>();
    }

    public void push(int x) {
        q2.offer(x);
        while (!q1.isEmpty()) {
            q2.offer(q1.poll());
        }
        java.util.Queue<Integer> temp = q1;
        q1 = q2;
        q2 = temp;
    }

    public int pop() {
        return q1.poll();
    }

    public int top() {
        return q1.peek();
    }

    public boolean empty() {
        return q1.isEmpty();
    }
}

